package controller; import javax.swing.*;import javax.swing.table.*;import java.awt.*;import model.Member;import service.*;import service.impl.*;import util.*;
public class MemberFrame extends JFrame{MemberService s=new MemberServiceImpl();DefaultTableModel m=new DefaultTableModel(new String[]{"ID","帳號","密碼","姓名","Email","電話","角色"},0);JTable table=new JTable(m);JTextField id=new JTextField(),acc=new JTextField(),pwd=new JTextField(),name=new JTextField(),email=new JTextField(),phone=new JTextField(),role=new JTextField("USER"); public MemberFrame(){setTitle("會員管理");UiStyle.frame(this);add(UiStyle.label("👤 會員管理 CRUD",30,20,350,40,26));JScrollPane sp=new JScrollPane(table);sp.setBounds(30,80,620,430);add(sp);int x=680,y=80;JTextField[] fs={id,acc,pwd,name,email,phone,role};String[] ls={"ID","帳號","密碼","姓名","Email","電話","角色"};for(int i=0;i<fs.length;i++){add(UiStyle.label(ls[i],x,y,80,25,13));fs[i].setBounds(x+75,y,210,30);add(fs[i]);y+=45;}JButton add=UiStyle.btn("新增/修改",680,410,130,38),del=UiStyle.btn("刪除",830,410,100,38),ref=UiStyle.btn("重新整理",680,465,250,38);add(add);add(del);add(ref);table.getSelectionModel().addListSelectionListener(e->pick());add.addActionListener(e->save());del.addActionListener(e->del());ref.addActionListener(e->load());load();}
 void load(){m.setRowCount(0);for(Member x:s.findAll())m.addRow(new Object[]{x.getId(),x.getAccount(),x.getPassword(),x.getName(),x.getEmail(),x.getPhone(),x.getRole()});}
 void pick(){int r=table.getSelectedRow();if(r<0)return;id.setText(m.getValueAt(r,0)+"");acc.setText(m.getValueAt(r,1)+"");pwd.setText(m.getValueAt(r,2)+"");name.setText(m.getValueAt(r,3)+"");email.setText(m.getValueAt(r,4)+"");phone.setText(m.getValueAt(r,5)+"");role.setText(m.getValueAt(r,6)+"");}
 void save(){int i=id.getText().isBlank()?0:Integer.parseInt(id.getText());s.save(new Member(i,acc.getText(),pwd.getText(),name.getText(),email.getText(),phone.getText(),role.getText()));load();}
 void del(){if(!id.getText().isBlank()){s.delete(Integer.parseInt(id.getText()));load();}}
}
